module RefModule(
    input clk,
    input load,
    input [7:0] data_in,
    output [7:0] data_out
);reg [7:0] obf_shift_reg;

    always @(posedge clk) begin
        if (load) begin
            obf_shift_reg <= data_in;
        end else begin
            obf_shift_reg <= {obf_shift_reg[6:0], obf_shift_reg[7]};
        end
    end

    assign data_out = obf_shift_reg;

endmodule
